const d=$input.first().json;
if(!d.business_id) throw new Error('Missing business_id');
const p=d.parameters||{};
return [{json:{business_id:d.business_id,task_id:d.task_id||null,campaign_name:p.campaign_name||'Test Campaign',channel:p.channel||'sms',target_count:p.target_count||100,expected_open_rate:p.expected_open_rate||0.35,expected_conversion_rate:p.expected_conversion_rate||0.05,cost_per_send:p.cost_per_send||0.01}}];

const p=$input.first().json;
const opens=Math.round(p.target_count*p.expected_open_rate);
const conversions=Math.round(p.target_count*p.expected_conversion_rate);
const cost=p.target_count*p.cost_per_send;
const avg_booking_value=120;
const projected_revenue=conversions*avg_booking_value;
const roi=((projected_revenue-cost)/cost*100).toFixed(1);
return [{json:{campaign_name:p.campaign_name,channel:p.channel,target_count:p.target_count,projected_opens:opens,projected_conversions:conversions,projected_revenue:projected_revenue,estimated_cost:cost.toFixed(2),roi_pct:roi,recommendation:roi>200?'LAUNCH — strong ROI':roi>50?'LAUNCH — acceptable ROI':'REVIEW — low ROI',business_id:p.business_id,task_id:p.task_id}}];
